#include <vector>
#include <unordered_map>
#include <algorithm>

std::pair<int, int> mostFrequent(int N, vector<int>& A) {
    std::unordered_map<int, int> freq;
    int max_freq = 0;
    int best_elem = 2e9; // Initialize larger than 10^9

    // Build frequency map
    for (int num : A) {
        freq[num]++;
    }

    // Find the most frequent and smallest element
    for (const auto& pair : freq) {
        int num = pair.first;
        int count = pair.second;

        if (count > max_freq) {
            max_freq = count;
            best_elem = num;
        } else if (count == max_freq && num < best_elem) {
            best_elem = num;
        }
    }

    return {best_elem, max_freq};
}

