int compare(const void* a, const void* b) {
    int int_a = *(const int*)a;
    int int_b = *(const int*)b;
    if (int_a < int_b) return -1;
    if (int_a > int_b) return 1;
    return 0;
}

int* mostFrequent(int N, int* A) {
    // Sort the array first
    qsort(A, N, sizeof(int), compare);

    int max_freq = 0;
    int best_elem = -1;

    int current_freq = 1;
    int current_elem = A[0];

    for (int i = 1; i < N; i++) {
        if (A[i] == current_elem) {
            current_freq++;
        } else {
            // Update max_freq. Strict '>' ensures we keep the smallest element in a tie
            if (current_freq > max_freq) {
                max_freq = current_freq;
                best_elem = current_elem;
            }
            current_elem = A[i];
            current_freq = 1;
        }
    }

    // Final check for the last group of elements in the array
    if (current_freq > max_freq) {
        max_freq = current_freq;
        best_elem = current_elem;
    }

    int* result = (int*)malloc(2 * sizeof(int));
    result[0] = best_elem;
    result[1] = max_freq;
    return result;
}

