function mostFrequent(N, A) {
    let freq = new Map();
    let maxFreq = 0;
    let bestElem = Infinity;

    // Build frequency map
    for (let i = 0; i < N; i++) {
        let num = A[i];
        let count = (freq.get(num) || 0) + 1;
        freq.set(num, count);
    }

    // Find the most frequent and smallest element
    for (let [num, count] of freq.entries()) {
        if (count > maxFreq) {
            maxFreq = count;
            bestElem = num;
        } else if (count === maxFreq && num < bestElem) {
            bestElem = num;
        }
    }

    return [bestElem, maxFreq];
}
